-- CNB Primaria - Comunicación y Lenguaje L 2 (segunda lengua) - Primero a Sexto Grado
-- Fuentes: .../Dosificación_de_los_aprendizajes_-_Área_de_Comunicación_y_Lenguaje_L_2_-_{Grado}
-- Nivel de detalle: competencia + sub-competencias

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
-- Primer Grado
('Primer Grado', 'Comunicación y Lenguaje L 2', '1. Responde con gestos, movimientos y oralmente a mensajes sencillos escuchados en la L 2.', ARRAY['1.1. Responde a preguntas y peticiones sencillas utilizando gestos y movimientos corporales.', '1.2. Identifica sonidos propios del idioma.', '1.3. Utiliza expresiones de cortesía al saludar en el aula y en la escuela.']),
('Primer Grado', 'Comunicación y Lenguaje L 2', '2. Identifica, visualmente, figuras, imágenes y palabras del vocabulario básico.', ARRAY['2.1. Asocia el nombre de objetos con las ilustraciones que los representan.', '2.2. Identifica los nombres de compañeras y compañeros, de familiares, de objetos personales y del aula cuando se presentan en forma escrita.', '2.3. Identifica signos y símbolos utilizados en la prevención de accidentes y desastres.']),
('Primer Grado', 'Comunicación y Lenguaje L 2', '3. Identifica fonemas, símbolos y grafías de la L 2 en diferentes contextos comunicativos.', ARRAY['3.1. Utiliza, en su comunicación oral y escrita, palabras y fonemas de la L 2 que son diferentes a los de la L 1.', '3.2. Forma familias de palabras partiendo de la raíz de palabras del vocabulario básico de la L 2.', '3.3. Valora los fonemas, símbolos y grafías de su L 1, L 2 y los de los otros idiomas de la comunidad.']),
('Primer Grado', 'Comunicación y Lenguaje L 2', '4. Utiliza la segunda lengua para comunicar oral y gráficamente ideas y sentimientos.', ARRAY['4.1. Utiliza los pronombres personales al comunicarse.', '4.2. Nombra animales, frutas y objetos de los distintos ambientes del hogar y del aula.', '4.3. Utiliza vocabulario básico relacionado con actividades cotidianas.']),

-- Segundo Grado
('Segundo Grado', 'Comunicación y Lenguaje L 2', '1. Utiliza el lenguaje verbal y no verbal en la expresión de sus ideas y emociones.', ARRAY['1.1. Utiliza gestos para precisar los mensajes que transmiten en una conversación.', '1.2. Utiliza información que obtiene de conversaciones.', '1.3. Intercambia, oralmente o por medio de gestos y movimientos, experiencias, gustos y sentimientos con otros y otras.']),
('Segundo Grado', 'Comunicación y Lenguaje L 2', '2. Utiliza la lectura de oraciones y relatos sencillos en la búsqueda de información o como recreación.', ARRAY['2.1. Identifica detalles importantes, secuencia de los eventos, sentimientos y emociones de los personajes en el material de lectura.', '2.2. Valora los mensajes expresados en las lecturas.', '2.3. Lee diferentes tipos de materiales de lectura.']),
('Segundo Grado', 'Comunicación y Lenguaje L 2', '3. Utiliza conocimientos básicos del sistema fonológico propio de la L 2 en la comprensión y expresión de ideas.', ARRAY['3.1. Utiliza, en la lectura, patrones de entonación y ritmo propios de la L 2.', '3.2. Identifica y pronuncia con claridad palabras con fonemas de la L 2.', '3.3. Interpreta el significado de signos, íconos y señales.']),
('Segundo Grado', 'Comunicación y Lenguaje L 2', '4. Redacta textos cortos siguiendo las normas de la L 2.', ARRAY['4.1. Identifica la estructura básica de la oración y de los párrafos.', '4.2. Describe los diferentes tipos de palabras que conforman la oración en la L 2.', '4.3. Redacta oraciones cortas con mensajes claros.']),

-- Tercer Grado
('Tercer Grado', 'Comunicación y Lenguaje L 2', '1. Utiliza la L 2 en forma verbal y no verbal al establecer comunicación con otros y otras.', ARRAY['1.1. Interpreta gestos, posturas e imágenes utilizadas en la comunicación oral.', '1.2. Interpreta el contenido de poemas, historias, cuentos, canciones y retahílas.', '1.3. Expresa oralmente sus ideas en forma ordenada y coherente.']),
('Tercer Grado', 'Comunicación y Lenguaje L 2', '2. Lee, con diferentes propósitos, materiales de lectura del contexto cultural de la L 2.', ARRAY['2.1. Interpreta mensajes de rótulos, carteles y señalizaciones frecuentemente utilizados en la escuela y en la comunidad.', '2.2. Utiliza patrones de entonación y ritmo propios de la L 2 en la lectura oral.', '2.3. Identifica los detalles importantes en el material de lectura.', '2.4. Establece la secuencia de los eventos y la relación de causa y efecto de los mismos.']),
('Tercer Grado', 'Comunicación y Lenguaje L 2', '3. Utiliza con propiedad los conocimientos básicos de los sistemas fonológico y ortográfico propios de la L 2.', ARRAY['3.1. Utiliza palabras con fonemas propios de la L 2 en sus expresiones orales.', '3.2. Utiliza patrones de acentuación y ritmo propios de la L 2.', '3.3. Aplica la ortografía básica de la L 2 al expresarse por escrito.']),
('Tercer Grado', 'Comunicación y Lenguaje L 2', '4. Expresa ideas, sentimientos y emociones en forma oral y escrita basándose en las normas de la L 2.', ARRAY['4.1. Formula oraciones estableciendo concordancia entre sujeto y predicado.', '4.2. Utiliza adecuadamente los momentos verbales en su comunicación.', '4.3. Utiliza palabras que califican y modifican al sustantivo.']),
('Tercer Grado', 'Comunicación y Lenguaje L 2', '5. Presenta resúmenes escritos siguiendo las reglas gramaticales básicas de la L 2.', ARRAY['5.1. Resume el contenido de textos orales y escritos.', '5.2. Elabora informes utilizando fichas y esquemas.', '5.3. Expone en forma ordenada y comprensible eventos y procesos utilizando fichas y esquemas informativos.']),

-- Cuarto Grado
('Cuarto Grado', 'Comunicación y Lenguaje L 2', '1. Utiliza el lenguaje oral en la expresión de ideas, emociones y sentimientos y en la interpretación del mensaje recibido.', ARRAY['1.1. Demuestra comprensión de los mensajes que escucha.', '1.2. Identifica diferentes tipos de mensajes orales y escritos.', '1.3. Organiza la información pertinente para responder a los mensajes recibidos.']),
('Cuarto Grado', 'Comunicación y Lenguaje L 2', '2. Utiliza el lenguaje no verbal como apoyo en la expresión de ideas, emociones y sentimientos.', ARRAY['2.1. Utiliza gestos y movimientos corporales como apoyo en la comunicación.', '2.2. Utiliza otras modalidades del lenguaje no verbal como apoyo en la comunicación.']),
('Cuarto Grado', 'Comunicación y Lenguaje L 2', '3. Utiliza la lectura de palabras, oraciones, párrafos, e historias para obtener y organizar información.', ARRAY['3.1. Lee, con fluidez, oraciones, párrafos e historias cortas en la L 2.', '3.2. Utiliza palabras de diferentes áreas de contenido demostrando comprensión de los conceptos que representan.', '3.3. Utiliza el orden alfabético para buscar y organizar información.']),
('Cuarto Grado', 'Comunicación y Lenguaje L 2', '4. Aplica, en su expresión oral y escrita, elementos básicos de la estructura de la palabra y de la oración.', ARRAY['4.1. Identifica, en palabras del vocabulario básico, los patrones de acentuación propios de la L 2.', '4.2. Identifica el elemento común a todos los vocablos que forman una familia de palabras y los elementos que determinan la diferencia entre una y otra.', '4.3. Utiliza los elementos que constituyen la estructura de una oración.', '4.4. Aplica la gramática de la L 2 en la expresión de sus ideas.', '4.5. Utiliza apropiadamente el vocabulario básico de la segunda lengua.']),
('Cuarto Grado', 'Comunicación y Lenguaje L 2', '5. Utiliza diferentes estrategias para adquirir y producir información, oralmente y por escrito, en la L 2.', ARRAY['5.1. Aplica diferentes estrategias para obtener información.', '5.2. Utiliza diferentes estrategias para organizar la información.', '5.3. Utiliza diferentes recursos para comunicar oralmente sus ideas.']),

-- Quinto Grado
('Quinto Grado', 'Comunicación y Lenguaje L 2', '1. Interpreta, con sentido crítico, mensajes de distinta índole utilizando el lenguaje oral.', ARRAY['1.1. Demuestra comprensión en situaciones de comunicación en las que se utiliza el lenguaje oral.', '1.2. Emite juicios con respecto a los mensajes recibidos.']),
('Quinto Grado', 'Comunicación y Lenguaje L 2', '2. Interpreta representaciones de situaciones reales o imaginarias, utilizando gestos, miradas, movimientos corporales y desplazamientos en la emisión de su respuesta.', ARRAY['2.1. Utiliza gestos y movimientos corporales para reforzar el significado de expresiones del lenguaje cotidiano.', '2.2. Asocia imágenes, señales, signos, símbolos y figuras con el mensaje que comunica.']),
('Quinto Grado', 'Comunicación y Lenguaje L 2', '3. Utiliza la lectura como medio para formar criterios, adquirir información y construir nuevos conocimientos.', ARRAY['3.1. Interpreta mensajes en textos recreativos.', '3.2. Identifica detalles importantes en textos informativos.', '3.3. Utiliza diferentes textos como apoyo para fundamentar la información con respecto a diferentes temas.']),
('Quinto Grado', 'Comunicación y Lenguaje L 2', '4. Aplica diferentes estrategias para derivar el significado de palabras desconocidas y su relación con la estructura de la oración, según la normativa de la L 2.', ARRAY['4.1. Utiliza el contexto para inferir el significado de palabras desconocidas.', '4.2. Utiliza el análisis fonológico para leer palabras desconocidas.', '4.3. Utiliza la estructura de las palabras para leer palabras desconocidas.', '4.4. Describe las palabras que constituyen parte de la estructura de la oración.', '4.5. Identifica los elementos que determinan la concordancia entre los diferentes elementos de la oración.']),
('Quinto Grado', 'Comunicación y Lenguaje L 2', '5. Utiliza las técnicas apropiadas en la redacción de textos narrativos e informativos.', ARRAY['5.1. Organiza la información que recaba durante actividades de observación.', '5.2. Elabora textos narrativos e informativos.', '5.3. Elabora textos de carácter epistolar.']),

-- Sexto Grado
('Sexto Grado', 'Comunicación y Lenguaje L 2', '1. Utiliza el lenguaje oral como medio de comunicación al discutir temas de interés personal y colectivo.', ARRAY['1.1. Argumenta sus opiniones con respecto a la información recibida.', '1.2. Participa en actividades de intercambio de información.', '1.3. Aplica normas de cortesía en las diferentes instancias en las que se da el intercambio de información.']),
('Sexto Grado', 'Comunicación y Lenguaje L 2', '2. Utiliza el lenguaje verbal y no verbal para responder a mensajes en situaciones de la vida cotidiana.', ARRAY['2.1. Infiere el significado de mensajes que se apoyan en el lenguaje no verbal.', '2.2. Asocia gestos, movimientos y desplazamientos con el mensaje que comunican.']),
('Sexto Grado', 'Comunicación y Lenguaje L 2', '3. Utiliza diferentes tipos de lectura en la documentación de sus juicios y opiniones.', ARRAY['3.1. Utiliza diferentes fuentes de información al elaborar sus argumentos.', '3.2. Utiliza diferentes estrategias lectoras para ubicar la información pertinente.', '3.3. Emite juicios críticos con respecto a lo expresado en las diferentes obras de referencia.']),
('Sexto Grado', 'Comunicación y Lenguaje L 2', '4. Aplica conocimientos de morfología, semántica y sintaxis de la L 2 en su expresión oral y escrita.', ARRAY['4.1. Aplica las reglas de pronunciación y acentuación, según la normativa de la L 2.', '4.2. Utiliza el conocimiento sobre la estructura de las palabras en la elaboración de textos escritos.', '4.3. Elabora párrafos utilizando la acentuación ortográfica y los signos de puntuación según la normativa de la L 2.']),
('Sexto Grado', 'Comunicación y Lenguaje L 2', '5. Aplica, en su expresión oral y escrita, los elementos que inciden en la corrección del lenguaje según la normativa de la L 2.', ARRAY['5.1. Utiliza, en la expresión de sus ideas, los diferentes tipos de palabras según la normativa de la L 2.', '5.2. Redacta textos narrativos de acuerdo con los requerimientos del momento y según la normativa de la L 2.', '5.3. Redacta textos poéticos de acuerdo con los requerimientos del momento y según la normativa de la L 2.', '5.4. Establece la diferencia entre textos poéticos y otros tipos de texto.']);
